import { useState, useEffect, useRef } from "react";


const IMG_COUPLE = "data:image/jpeg;base64,";
const IMG_FAMILY = "data:image/jpeg;base64,";
const IMG_PORTRAIT = "data:image/jpeg;base64,";
const IMG_PET = "data:image/jpeg;base64,";


const GOLD = "#C9A84C";
const CHARCOAL = "#2C2C2C";
const BEIGE = "#FAF7F2";
const LIGHT_GOLD = "#F0E6C8";
const SOFT_GRAY = "#6B6B6B";

const SketchPlaceholder = ({ type = "portrait", label = "", style = {} }) => {
  // Map types to real sketch images
  const realImages = {
    family:    IMG_FAMILY,
    portrait:  IMG_PORTRAIT,
    pet:       IMG_PET,
    couple:    IMG_COUPLE,
    celebrity: IMG_PORTRAIT,
  };
  const imgSrc = realImages[type] || IMG_PORTRAIT;
  return (
    <div style={{width:"100%",height:"100%",position:"relative",overflow:"hidden",...style}}>
      <img 
        src={imgSrc} 
        alt={label || type + " sketch"} 
        style={{width:"100%",height:"100%",objectFit:"cover",display:"block",filter:"contrast(1.05) brightness(0.98)"}}
      />
      {label && (
        <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"8px 12px",background:"linear-gradient(transparent,rgba(0,0,0,0.5))",color:"#fff",fontSize:"11px",fontFamily:"'Playfair Display',serif",fontStyle:"italic",textAlign:"center",letterSpacing:"1px"}}>
          {label}
        </div>
      )}
    </div>
  );
};

const Stars = ({ n = 5 }) => <span style={{color:GOLD,fontSize:"16px"}}>{"★".repeat(n)}</span>;
const BASE_PRICES = { Portrait:299, Couple:399, Family:499, Pet:399 };
const SIZE_MULT = { A4:1, A3:1.4, Custom:1.7 };

function BeforeAfterSlider({ type, label }) {
  const [pos, setPos] = useState(50);
  const [dragging, setDragging] = useState(false);
  const ref = useRef();
  const handleMove = (e) => {
    if (!dragging) return;
    const rect = ref.current.getBoundingClientRect();
    const x = (e.touches?.[0]?.clientX || e.clientX) - rect.left;
    setPos(Math.max(5, Math.min(95, (x/rect.width)*100)));
  };
  return (
    <div style={{borderRadius:"16px",overflow:"hidden",boxShadow:"0 8px 30px rgba(0,0,0,0.1)",background:"#fff"}}>
      <div ref={ref} style={{position:"relative",height:"300px",cursor:"ew-resize",userSelect:"none"}}
        onMouseDown={()=>setDragging(true)} onMouseUp={()=>setDragging(false)}
        onMouseLeave={()=>setDragging(false)} onMouseMove={handleMove}
        onTouchStart={()=>setDragging(true)} onTouchEnd={()=>setDragging(false)} onTouchMove={handleMove}>
        <div style={{position:"absolute",inset:0}}><SketchPlaceholder type={type} label={`${label} Sketch`}/></div>
        <div style={{position:"absolute",inset:0,clipPath:`inset(0 ${100-pos}% 0 0)`}}>
          <div style={{width:"100%",height:"100%",background:"linear-gradient(135deg,#d4a574,#c4956a,#b8854f)",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <div style={{textAlign:"center",color:"rgba(255,255,255,0.8)"}}>
              <div style={{fontSize:"40px",marginBottom:"8px"}}>📷</div>
              <div style={{fontSize:"13px",letterSpacing:"2px"}}>ORIGINAL PHOTO</div>
            </div>
          </div>
        </div>
        <div style={{position:"absolute",top:0,bottom:0,left:`${pos}%`,width:"2px",background:GOLD,transform:"translateX(-50%)"}}>
          <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",width:"36px",height:"36px",borderRadius:"50%",background:GOLD,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 15px rgba(201,168,76,0.5)",color:"#fff",fontSize:"13px",fontWeight:"700"}}>⟺</div>
        </div>
        <div style={{position:"absolute",bottom:"10px",left:"10px",background:"rgba(0,0,0,0.6)",color:"#fff",padding:"3px 10px",borderRadius:"50px",fontSize:"11px"}}>PHOTO</div>
        <div style={{position:"absolute",bottom:"10px",right:"10px",background:GOLD,color:"#fff",padding:"3px 10px",borderRadius:"50px",fontSize:"11px"}}>SKETCH</div>
      </div>
      <div style={{padding:"14px 18px",borderTop:"1px solid #f0ebe0",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{fontFamily:"'Playfair Display',serif",fontSize:"16px",fontWeight:"600"}}>{label}</div>
        <div style={{fontSize:"11px",color:"#aaa",letterSpacing:"1px"}}>← Drag →</div>
      </div>
    </div>
  );
}

